// Dice helpers for the combat engine. Consumes the shared seeded Rng (play/rng.ts) so rolls
// are replay-stable; roll order is part of the engine contract - never reorder rng calls.

import { rollDie } from '../play/rng.ts'
import type { Rng } from '../play/rng.ts'
import { CombatError } from './types.ts'
import type { DiceExpr } from './types.ts'

const DICE_RE = /^\s*(\d+)d(\d+)\s*(?:([+-])\s*(\d+))?\s*$/i

/** Parse "1d8+3" / "2d6" / "1d10-1" (the npcs.stat_block attack damage shape). */
export function parseDiceExpr(text: string): DiceExpr {
  const m = DICE_RE.exec(text)
  if (!m) throw new CombatError(`Unparseable dice expression: "${text}"`)
  const bonus = m[3] === undefined ? 0 : (m[3] === '-' ? -1 : 1) * Number(m[4])
  return { count: Number(m[1]), sides: Number(m[2]), bonus }
}

export function formatDiceExpr(expr: DiceExpr): string {
  const suffix = expr.bonus === 0 ? '' : expr.bonus > 0 ? `+${expr.bonus}` : `${expr.bonus}`
  return `${expr.count}d${expr.sides}${suffix}`
}

/** Average result, for the heuristic's attack ranking - no rng consumed. */
export function expectedDamage(expr: DiceExpr): number {
  return expr.count * ((expr.sides + 1) / 2) + expr.bonus
}

export function rollDiceExpr(rng: Rng, expr: DiceExpr, extraDice = 0): { rolls: number[]; sum: number } {
  const rolls: number[] = []
  for (let i = 0; i < expr.count + extraDice; i++) rolls.push(rollDie(rng, expr.sides))
  return { rolls, sum: rolls.reduce((a, b) => a + b, 0) }
}

/**
 * A d20 under advantage state: two dice rolled (highest/lowest used) for adv/dis, one otherwise.
 * Both dice always appear in the breakdown so the log can show the discarded die.
 */
export function rollD20(rng: Rng, advantage: 'none' | 'advantage' | 'disadvantage'): { dice: number[]; used: number } {
  const first = rollDie(rng, 20)
  if (advantage === 'none') return { dice: [first], used: first }
  const second = rollDie(rng, 20)
  const used = advantage === 'advantage' ? Math.max(first, second) : Math.min(first, second)
  return { dice: [first, second], used }
}
